async function run(input, values, runCommand, cwd, askUserQuestion, vscode) {
  const [[env]] = await askUserQuestion([
    {
      question: '工作流执行环境',
      options: [
        { label: '主工作区', desc: '在当前目录执行' },
        { label: 'worktree', desc: '创建worktree执行' },
      ],
      hiddenOther: true,
    },
  ])
  let absPath = undefined
  if (env === 'worktree') {
    let [[base]] = await askUserQuestion([
      {
        question: 'worktree基准分支，将创建worktree和新分支',
        options: [{ label: '当前分支' }, { label: 'main' }, { label: 'develop' }],
      },
    ])
    base = base === '当前分支' ? '' : ' ' + base
    const suffix = Math.random().toString(36).slice(2, 10)
    const branchName = `agent-flow-dev/${suffix}`
    const worktreePath = `.claude/worktrees/${suffix}`
    await runCommand(`git worktree add --no-track -b ${branchName} ${worktreePath}` + base)
    absPath = (await runCommand(`git -C ${worktreePath} rev-parse --show-toplevel`)).trim()
  }
  return {
    output_name: '准备完成',
    content: input,
    cwd: absPath,
    overwrite: {
      work_mode: 'task',
      outputs: [{ output_name: '分析完成', require_confirm: true }],
    },
  }
}

