      throw new Error('')
    }
    return {
      output_name:'初始化完成',
      values: { tasks: JSON.stringify(parsed, null, 2), next: '0'}
    }
  } catch {
    return {
      output_name: '格式错误'
    }
  }
}

async function run(input, values, runCommand, cwd, askUserQuestion, vscode) {
  const next = parseInt(values.next)
  const tasks = JSON.parse(values.tasks)
  if(next === tasks.length || tasks.length === 0){
    return {
      output_name: '全部子任务执行完毕',
      content: '验证用户需求是否实现'
    }
  }
  const current_task = tasks[next>=0 && next<tasks.length ? next: 0]
  return {
    content: '依据<task_description>执行任务',
    output_name: '执行子任务',
    values: { current_task, next: `${next + 1}` }
  }
}

